import React from "react";

// Dynamic data for services with images
const services = [
  {
    id: 1,
    name: "Hotel Booking",
    description: "Book the best hotels at your favorite destinations.",
    image: "https://images.unsplash.com/photo-1568605114967-8130f3a36994?fit=crop&w=400"
  },
  {
    id: 2,
    name: "Makeup",
    description: "hairsalon and makeup.",
    image: "https://images.unsplash.com/photo-1508214751196-bcfd4ca60f91?fit=crop&w=400"
  },
  {
    id: 3,
    name: "Car Rentals",
    description: "Rent cars for your trips with flexible options.",
    image: "https://images.unsplash.com/photo-1533473359331-0135ef1b58bf?fit=crop&w=400"
  },
  {
    id: 4,
    name: "Tour Guides",
    description: "Get local guides to explore cities like a pro.",
    image: "https://images.unsplash.com/photo-1438761681033-6461ffad8d80?fit=crop&w=400"
  }
];

function Services() {
  return (
    <div style={{ padding: "20px" }}>
      <h1>Our Services</h1>
      <div style={{ display: "flex", flexWrap: "wrap", gap: "20px" }}>
        {services.map(service => (
          <div
            key={service.id}
            style={{
              border: "1px solid #ccc",
              borderRadius: "10px",
              width: "300px",
              overflow: "hidden",
              textAlign: "center",
              background: "#f9f9f9",
              boxShadow: "0 2px 5px rgba(0,0,0,0.1)"
            }}
          >
            <img
              src={service.image}
              alt={service.name}
              style={{ width: "100%", height: "200px", objectFit: "cover" }}
            />
            <div style={{ padding: "10px" }}>
              <h3>{service.name}</h3>
              <p>{service.description}</p>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}

export default Services;
